/* SapCancelResultBatchMapper.xml saveCancelResult */
UPDATE TORDER_BATCH_CANCEL_RESULT
   SET PRCSYN = CASE WHEN #{saptransfailyn}='Y' THEN 'N' ELSE 'Y' END
     , PRCSDATE = #{interfaceDate}
     , BATEXECID = #{batExecId}
     , UPDATEDATE = #{interfaceDate}
     , UPDATEURKEY = #{interfaceUrkey}
 WHERE BATCHKEY  = #{batchkey} 
   AND OWKEY = #{owkey} 
   AND EXTERNORDERKEY = #{externorderkey}
